using BuildingBlocks.Authentication; using BuildingBlocks.Endpoints; using BuildingBlocks.Export; using BuildingBlocks.Grids; using BuildingBlocks.Http; using BuildingBlocks.Messaging; using Expenses.Contracts; using Expenses.Features; using Expenses.Persistence; using Microsoft.AspNetCore.Builder; using Microsoft.AspNetCore.Http; using Microsoft.AspNetCore.Routing; using Microsoft.EntityFrameworkCore;
namespace Expenses.Endpoints;
/** <summary>Expense endpoints.</summary> */ public sealed class ExpensesEndpoints:IEndpoint
{ /** <inheritdoc/> */ public void MapEndpoint(IEndpointRouteBuilder app){var g=app.MapGroup(ExpensesRoutes.Base).WithTags(ExpensesRoutes.Tag);g.MapPost("",async(CreateExpenseRequest r,IDispatcher d,CancellationToken ct)=>(await d.Send<ExpenseResponse>(new CreateExpenseCommand(r.Category,r.Amount,r.Date,r.Payee,r.Notes),ct)).ToHttpResult(v=>Results.Created($"{ExpensesRoutes.Base}/{v.Id}",v))).RequirePermission("expenses.write");g.MapPut("/{id:guid}",async(Guid id,UpdateExpenseRequest r,IDispatcher d,CancellationToken ct)=>(await d.Send<ExpenseResponse>(new UpdateExpenseCommand(id,r.Category,r.Amount,r.Date,r.Payee,r.Notes),ct)).ToHttpResult()).RequirePermission("expenses.write");g.MapDelete("/{id:guid}",async(Guid id,IDispatcher d,CancellationToken ct)=>(await d.Send<bool>(new DeleteExpenseCommand(id),ct)).ToHttpResult(_=>Results.NoContent())).RequirePermission("expenses.delete");g.MapGet("/{id:guid}",async(Guid id,IDispatcher d,CancellationToken ct)=>(await d.Send<ExpenseResponse>(new GetExpenseByIdQuery(id),ct)).ToHttpResult()).RequirePermission("expenses.read");g.MapPost("/grid",async(GridQuery r,IDispatcher d,CancellationToken ct)=>(await d.Send<PagedResult<ExpenseResponse>>(new GetExpensesGridQuery(r),ct)).ToHttpResult()).RequirePermission("expenses.read");g.MapPost("/export",ExportAsync).RequirePermission("expenses.export");}
private static async Task<IResult> ExportAsync(ExpenseExportRequest r,ExpensesDbContext db,IGridExporterFactory factory,CancellationToken ct){var q=db.Expenses.AsNoTracking().ApplyGridQuery(r.Grid,ExpenseGrid.Fields);if(q.IsFailure)return q.ToHttpResult();var rows=await q.Value.Take(GridExportLimits.MaxRows).Select(ExpenseGrid.Projection).ToListAsync(ct);ExportColumn[] cols=[new("Category","الفئة",GridFieldType.Text),new("Amount","المبلغ",GridFieldType.Number),new("Date","التاريخ",GridFieldType.Date),new("Payee","المستفيد",GridFieldType.Text)];var bytes=factory.For(r.Format).Export(rows,cols,"المصروفات");return Results.File(bytes,r.Format==ExportFormat.Xlsx?"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet":"application/pdf",$"expenses.{(r.Format==ExportFormat.Xlsx?"xlsx":"pdf")}");}}
